        1: { cellWidth: 55, halign: 'right' },
        2: { cellWidth: 'auto' },
      },
      margin: { left: 14, right: 14 },
    });

    // ΓöÇΓöÇ Transaction ledger title
    const y1 = ((doc as any).lastAutoTable?.finalY ?? 100) + 10;
    doc.setFont('helvetica', 'bold');
