const formatMembership = (m: string) => {
  const map: Record<string, string> = {
    free:        'Free Plan',
    premium_1m:  'Pro (1M)',
    premium_3m:  'Pro (3M)',
    premium_6m:  'Pro (6M)',
    premium_12m: 'Pro (12M)',
  };
  return map[m] || m;
