// ΓöÇΓöÇ Logo loader (server-side filesystem read with diagnostics) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function getLogoBase64(): string {
  const candidates = [
    path.join(process.cwd(), 'public', 'logo.png'),
    path.resolve('./public/logo.png'),
    path.join(process.cwd(), '..', 'public', 'logo.png'),
    path.join(process.cwd(), '.next', 'standalone', 'public', 'logo.png')
  ];

  for (const logoPath of candidates) {
    try {
      if (fs.existsSync(logoPath)) {
        const buf = fs.readFileSync(logoPath);
        return `data:image/png;base64,${buf.toString('base64')}`;
      }
    } catch (e: any) {
      console.error(`Error reading logo from path ${logoPath}:`, e.message);
    }
  }

  console.error(" getLogoBase64 failed: public/logo.png not found in candidates:", candidates);
  return '';
}

// ΓöÇΓöÇ PDF header ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function drawPdfHeader(
  doc: any,
  title: string,
  primary: [number, number, number],
  logoBase64: string
) {
  const pw = doc.internal.pageSize.width;

  // Accent bar
  doc.setFillColor(...primary);
  doc.rect(0, 0, pw, 5, 'F');

  // Logo
  let textX = 14;
  if (logoBase64) {
    try {
      doc.addImage(logoBase64, 'PNG', 14, 8, 48, 12);
      textX = 66;
    } catch (e: any) {
      console.error("jsPDF addImage failed:", e.message);
    }
  } else {
    console.warn("drawPdfHeader: logoBase64 string is empty");
  }

  // Company name
  doc.setTextColor(30, 41, 59);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(18);
  doc.text('Latexify Studio', textX, 16);

  // Tagline
  doc.setFont('helvetica', 'italic');
  doc.setFontSize(8);
  doc.setTextColor(100, 116, 139);
  doc.text('Professional LaTeX Editorial for Researchers', textX, 22);

  // Contact (right)
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(7.5);
  doc.setTextColor(100, 116, 139);
  doc.text('www.latexify.io',     pw - 14, 13, { align: 'right' });
  doc.text('contact@latexify.io', pw - 14, 18, { align: 'right' });
  doc.text('Bangalore, India',    pw - 14, 23, { align: 'right' });

  // Divider
  doc.setDrawColor(203, 213, 225);
  doc.setLineWidth(0.4);
  doc.line(14, 27, pw - 14, 27);

  // Title
  doc.setTextColor(...primary);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  doc.text(title, 14, 34);

  // Date
  doc.setTextColor(148, 163, 184);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(7.5);
  doc.text(`Exported: ${new Date().toLocaleString('en-IN')}`, pw - 14, 34, { align: 'right' });
}

// ΓöÇΓöÇ PDF footer (3 rows, no overlap) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function drawPdfFooter(doc: any, primary: [number, number, number]) {
  const pageCount = doc.getNumberOfPages();
  const pw = doc.internal.pageSize.width;
  const ph = doc.internal.pageSize.height;

  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i);

    // Divider line
    doc.setDrawColor(203, 213, 225);
    doc.setLineWidth(0.4);
    doc.line(14, ph - 22, pw - 14, ph - 22);

    // Row 1 ΓÇö left: source | right: page
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(7.5);
    doc.setTextColor(148, 163, 184);
    doc.text('Latexify Super Admin Console', 14, ph - 16);
    doc.text(`Page ${i} / ${pageCount}`, pw - 14, ph - 16, { align: 'right' });

    // Row 2 ΓÇö center: confidential
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(7);
    doc.setTextColor(220, 38, 38);
    doc.text('CONFIDENTIAL ΓÇö INTERNAL USE ONLY', pw / 2, ph - 10, { align: 'center' });

    // Row 3 ΓÇö copyright
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(6.5);
    doc.setTextColor(148, 163, 184);
    doc.text('┬⌐ 2026 Latexify Studio. All rights reserved.', pw / 2, ph - 5, { align: 'center' });
  }
}

async function fetchUsersData() {
  const users = await prisma.user.findMany({
    orderBy: { createdAt: 'desc' },
    include: {
      projects: { select: { id: true } },
      blacklistRecords: { orderBy: { createdAt: 'desc' }, take: 1, select: { reason: true } },
      sessionActivities: { orderBy: { createdAt: 'desc' }, take: 1, select: { ipAddress: true, location: true } },
    },
  });

  const logs = await prisma.aiUsageLog.groupBy({
    by: ['userId'],
    _sum: { totalTokens: true },
  });
  const tokenMap: Record<string, number> = {};
  logs.forEach((l: any) => { if (l.userId) tokenMap[l.userId] = l._sum.totalTokens || 0; });

  return users.map((u: any) => ({
    id: u.id,
    name: u.name || 'Unnamed Scholar',
    email: u.email,
    role: u.role || 'user',
    status: u.status || 'active',
    membership: formatMembership(u.membership || 'free'),
    membershipRaw: u.membership || 'free',
    membershipExpiresAt: u.membershipExpiresAt || null,
    points: u.points || 0,
    aiTokensUsed: tokenMap[u.id] || 0,
    projectCount: u.projects?.length || 0,
    lastIp: u.sessionActivities?.[0]?.ipAddress || 'N/A',
    lastLocation: u.sessionActivities?.[0]?.location || 'N/A',
    blacklistReason: u.blacklistRecords?.[0]?.reason || 'None',
    blockedUntil: u.blockedUntil || null,
    createdAt: u.createdAt,
  }));
}

