          const data = await res.json();
          if (data.success) {
            setIsLive(data.isLive);
          }
        }
      } catch (err) {
        console.warn("[ChatWidget] Failed to check admin live status:", err);
      }
    };
    checkLiveStatus();
    const interval = setInterval(checkLiveStatus, 15000);
    return () => clearInterval(interval);
  }, []);

  // Poll messages if chat is open and we have a session
  useEffect(() => {
    if (!isOpen || !chatSession?.id) return;

    const fetchMessages = async () => {
      try {
        const res = await fetch(`/api/chat/message?sessionId=${chatSession.id}`);
        if (res.ok) {
          const data = await res.json();
          if (data.success) {
            setMessages(data.messages || []);
            if (data.sessionStatus !== "open") {
              // Session closed by admin
              setChatSession((prev: any) => prev ? { ...prev, status: data.sessionStatus } : null);
            }
          }
        }
      } catch (err) {
        console.warn("[ChatWidget] Failed to poll messages:", err);
      }
    };

    fetchMessages();
    const interval = setInterval(fetchMessages, 3000);
    return () => clearInterval(interval);
  }, [isOpen, chatSession?.id]);

  // Scroll to bottom on new messages
  useEffect(() => {
    messageEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isOpen]);

  const handleOpenWidget = async () => {
    if (!session?.user) return;
    setLoadingSession(true);
    try {
      const res = await fetch("/api/chat/session");
      if (res.status === 403) {
        setShowPremiumModal(true);
        setLoadingSession(false);
        return;
      }
      if (res.ok) {
        const data = await res.json();
        if (data.success && data.session) {
          setChatSession(data.session);
          setIsOpen(true);
        }
      } else {
        setShowPremiumModal(true);
      }
    } catch (err) {
      console.warn("[ChatWidget] Error starting chat session:", err);
    } finally {
      setLoadingSession(false);
    }
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim() || !chatSession?.id) return;

    const text = newMessage;
    setNewMessage("");

    try {
      const res = await fetch("/api/chat/message", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          sessionId: chatSession.id,
          content: text
        })
      });
      if (res.ok) {
        const data = await res.json();
        if (data.success && data.message) {
          setMessages(prev => [...prev, data.message]);
        }
      }
    } catch (err) {
      console.error("[ChatWidget] Send message error:", err);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0 || !chatSession?.id) return;
    const file = files[0];

    setUploading(true);
    const formData = new FormData();
    formData.append("file", file);

    try {
      const uploadRes = await fetch("/api/chat/upload", {
        method: "POST",
        body: formData
      });
      if (!uploadRes.ok) throw new Error("Upload failed");
      const uploadData = await uploadRes.json();

      if (uploadData.url) {
        const messageRes = await fetch("/api/chat/message", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            sessionId: chatSession.id,
            content: `Sent attachment: ${file.name}`,
            attachmentUrl: uploadData.url,
            attachmentName: uploadData.filename
          })
        });

        if (messageRes.ok) {
          const msgData = await messageRes.json();
          if (msgData.success && msgData.message) {
            setMessages(prev => [...prev, msgData.message]);
          }
        }
      }
    } catch (err) {
      console.error("[ChatWidget] Attachment upload failed:", err);
    } finally {
      setUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = "";
    }
  };

  return (
    <>
      {/* Floating Chat Trigger Button */}
      {!isOpen && (
        <button
          onClick={handleOpenWidget}
          disabled={loadingSession}
          className="fixed bottom-6 right-6 z-[9999] p-4 rounded-full shadow-2xl transition-all duration-300 hover:scale-105 active:scale-95 flex items-center justify-center gap-2 group text-white font-bold bg-gradient-to-r from-violet-600 to-indigo-600 dark:from-violet-500 dark:to-indigo-500"
        >
          <span className="material-symbols-outlined text-2xl">chat</span>
          <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-500 text-sm whitespace-nowrap">
            {loadingSession ? "Connecting..." : isLive ? "Live Chat" : "Support"}
          </span>
          <span className={`w-2.5 h-2.5 rounded-full border border-white/20 ${isLive ? "bg-green-400 animate-pulse" : "bg-zinc-400"}`}></span>
        </button>
      )}

      {/* Premium Membership Restrict Dialog */}
      {showPremiumModal && (
        <div className="fixed inset-0 z-[10000] flex items-center justify-center p-4 bg-black/75 backdrop-blur-sm animate-in fade-in duration-200">
          <div 
            className="rounded-3xl border text-center shadow-2xl p-8 bg-zinc-900 border-zinc-800 text-white flex flex-col items-center justify-center"
            style={{ width: '460px', maxWidth: '90vw', minHeight: '320px' }}
          >
            <span className="material-symbols-outlined text-6xl text-amber-400 animate-bounce" style={{ fontVariationSettings: "'FILL' 1" }}>workspace_premium</span>
            <h3 className="text-2xl font-black mt-4 tracking-tight" style={{ color: '#fbbf24' }}>Premium Feature</h3>
            <p className="text-sm mt-3 leading-relaxed text-zinc-300 font-medium px-2">
              This live chat is only for premium members, please upgrade your membership for hassle-free writing.
            </p>
            <div className="mt-8 flex flex-col gap-3 w-full px-4">
              <button
                onClick={() => {
                  setShowPremiumModal(false);
                  window.location.href = "/dashboard?tab=billing";
                }}
                className="w-full py-3 rounded-xl font-bold bg-amber-400 hover:bg-amber-500 text-zinc-950 transition-colors uppercase tracking-wider text-xs"
              >
                UPGRADE NOW
              </button>
              <button
                onClick={() => setShowPremiumModal(false)}
                className="w-full py-3 rounded-xl font-bold border border-zinc-700 hover:bg-zinc-800 text-zinc-300 transition-colors text-xs"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Active Live Chat Window */}
      {isOpen && chatSession && (
        <div className="fixed bottom-6 right-6 z-[9999] w-[380px] sm:w-[480px] h-[550px] rounded-3xl border shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-300 bg-zinc-950 border-zinc-800 text-white">
          {/* Header */}
          <div className="p-4 border-b border-zinc-800 bg-zinc-900 flex justify-between items-center">
            <div className="flex items-center gap-2">
              <span className={`w-3 h-3 rounded-full ${isLive ? "bg-green-400 animate-pulse" : "bg-zinc-400"}`}></span>
              <div>
                <p className="text-sm font-bold leading-none">Support Representative</p>
                <p className="text-[10px] text-zinc-400 mt-1">
                  {isLive ? "Admin is online" : "Admin is offline - drop message"}
                </p>
              </div>
            </div>
            <button
              onClick={() => setIsOpen(false)}
              className="p-1 hover:bg-zinc-800 rounded-full transition-colors"
            >
              <span className="material-symbols-outlined text-lg block">close</span>
            </button>
          </div>

          {/* Messages List */}
          <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scroll">
            {messages.length === 0 ? (
              <div className="text-center py-8 text-zinc-500 text-xs">
                Send a message to start conversation.
              </div>
            ) : (
              messages.map(m => {
                const isSystem = m.content.startsWith("[SYSTEM_NOTIFICATION]");
                if (isSystem) {
                  const cleanedText = m.content.replace("[SYSTEM_NOTIFICATION]", "").trim();
                  return (
                    <div key={m.id} className="text-center my-3">
                      <span className="text-[9px] px-2 py-0.5 rounded bg-zinc-800/80 text-zinc-400 border border-zinc-800 uppercase tracking-widest font-black">
                        {cleanedText}
                      </span>
                    </div>
                  );
                }

                const isMe = m.senderType === "user";
                return (
                  <div key={m.id} className={`flex ${isMe ? "justify-end" : "justify-start"}`}>
                    <div
                      className={`max-w-[80%] rounded-2xl px-3 py-2 text-xs relative ${
                        isMe
                          ? "bg-indigo-600 text-white rounded-tr-none"
                          : "bg-zinc-800 text-zinc-100 rounded-tl-none"
                      }`}
                    >
                      {m.attachmentUrl ? (
                        <div className="space-y-1.5">
                          <div className="flex items-center gap-1.5 font-bold border-b border-white/10 pb-1 mb-1">
                            <span className="material-symbols-outlined text-sm">attachment</span>
                            <span className="truncate max-w-[150px]">{m.attachmentName || "File Attachment"}</span>
                          </div>
                          {m.attachmentUrl.match(/\.(jpeg|jpg|gif|png|webp)/i) ? (
                            <img
                              src={m.attachmentUrl}
                              alt={m.attachmentName || "Upload"}
                              className="rounded max-w-full max-h-40 object-cover border border-white/5 cursor-pointer"
                              onClick={() => window.open(m.attachmentUrl || "", "_blank")}
                            />
                          ) : (
                            <a
                              href={m.attachmentUrl}
                              target="_blank"
                              rel="noreferrer"
                              className="inline-flex items-center gap-1 hover:underline text-amber-300 font-bold"
                            >
                              Download File
                              <span className="material-symbols-outlined text-[10px]">open_in_new</span>
                            </a>
                          )}
                        </div>
                      ) : (
                        <p className="leading-relaxed break-words">{m.content}</p>
                      )}
                      <span className="block text-[8px] text-white/40 text-right mt-1">
                        {new Date(m.createdAt).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    </div>
                  </div>
                );
              })
            )}
            <div ref={messageEndRef} />
          </div>

          {/* Attachment Input Form */}
          {chatSession.status === "open" ? (
            <form onSubmit={handleSendMessage} className="p-3 border-t border-zinc-800 bg-zinc-900/50 flex gap-2 items-center">
              <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileUpload}
                className="hidden"
                accept="image/*,.pdf,.doc,.docx,.txt,.zip,.tex"
              />
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                disabled={uploading}
                className="p-2 hover:bg-zinc-800 text-zinc-400 rounded-xl transition-colors disabled:opacity-50"
                title="Add Attachment"
              >
                {uploading ? (
                  <span className="material-symbols-outlined animate-spin text-sm">sync</span>
                ) : (
                  <span className="material-symbols-outlined text-lg block">attachment</span>
                )}
              </button>
              <input
                type="text"
                value={newMessage}
                onChange={e => setNewMessage(e.target.value)}
                placeholder="Type your message..."
                className="flex-1 bg-zinc-800 border border-zinc-700 text-white rounded-xl px-3 py-1.5 text-xs outline-none focus:ring-1 focus:ring-indigo-500"
              />
              <button
                type="submit"
                disabled={!newMessage.trim()}
                className="p-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl transition-colors disabled:opacity-50"
              >
                <span className="material-symbols-outlined text-sm block">send</span>
              </button>
            </form>
          ) : (
            <div className="p-4 text-center text-xs bg-zinc-900 border-t border-zinc-800 text-zinc-400 font-bold">
              This session was terminated. Start a new chat session to continue.
              <button
                onClick={handleOpenWidget}
                className="block mx-auto mt-2 text-indigo-400 hover:underline"
              >
                Start New Session
              </button>
            </div>
          )}
        </div>
      )}
    </>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Wifi, WifiOff, Activity } from "lucide-react";
import { useRouter } from "next/navigation";
import { 
  isSyncableUrl, 
  enqueueRequest, 
  replaySyncQueue, 
  cacheGetResponse, 
  getCachedGetResponse 
} from "@/lib/offlineSync";

export default function InternetMonitor() {
  const [status, setStatus] = useState<"online" | "offline" | "slow" | "restored">("online");
  const [isVisible, setIsVisible] = useState(false);
  const router = useRouter();
  const prevStatusRef = useRef<string>("online");

  // Handle connection events and Telemetry Speed
  useEffect(() => {
    const updateStatus = () => {
      if (!navigator.onLine) {
        setStatus("offline");
        setIsVisible(true);
      } else {
        const connection = (navigator as any).connection;
        if (connection && (connection.effectiveType === "slow-2g" || connection.effectiveType === "2g")) {
          setStatus("slow");
          setIsVisible(true);
        } else {
          // Check if we are restoring from an offline/slow state
          if (prevStatusRef.current === "offline" || prevStatusRef.current === "slow") {
            setStatus("restored");
            setIsVisible(true);

            // Dispatch custom restored event for page hooks
            window.dispatchEvent(new Event("online-restored"));

            // Trigger background queue replay
            replaySyncQueue();

            // Background pull server components data
            router.refresh();

            const timer = setTimeout(() => {
              setStatus("online");
              setIsVisible(false);
            }, 4000);
            return () => clearTimeout(timer);
          } else {
            setStatus("online");
            setIsVisible(false);
          }
        }
      }
    };

    window.addEventListener("online", updateStatus);
    window.addEventListener("offline", updateStatus);

    const connection = (navigator as any).connection;
    if (connection) {
      connection.addEventListener("change", updateStatus);
    }

    updateStatus();

    return () => {
      window.removeEventListener("online", updateStatus);
      window.removeEventListener("offline", updateStatus);
      if (connection) {
        connection.removeEventListener("change", updateStatus);
      }
    };
  }, [router]);

  // Keep track of previous status to detect restored state transitions
  useEffect(() => {
    prevStatusRef.current = status;
  }, [status]);

  // Handle scroll lock (overflow: hidden) when offline
  useEffect(() => {
    if (status === "offline") {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }
    return () => {
      document.body.style.overflow = "";
    };
  }, [status]);

  // Server heartbeat: periodically ping /api/health to verify real connectivity
  useEffect(() => {
    if (status === "offline") return; // Don't heartbeat while already offline

    const heartbeat = async () => {
      try {
        const controller = new AbortController();
        const timeout = setTimeout(() => controller.abort(), 8000);
        const res = await fetch("/api/health", { method: "GET", signal: controller.signal, cache: "no-store" });
        clearTimeout(timeout);
        if (!res.ok) {
          // Server responded but with error ΓÇö server is reachable, not offline
          console.log("[InternetMonitor] Health check returned", res.status, "ΓÇö server reachable");
        }
      } catch (err: any) {
        // Only force offline if navigator.onLine is also false (real disconnect)
        // OR if it's a true network error (not abort/timeout)
        if (!navigator.onLine) {
          console.warn("[InternetMonitor] Heartbeat failed + navigator.onLine=false ΓåÆ offline");
          setStatus("offline");
          setIsVisible(true);
        } else {
          console.warn("[InternetMonitor] Heartbeat failed but navigator.onLine=true ΓÇö server may be restarting, not forcing offline");
        }
      }
    };

    // Check every 30 seconds
    const interval = setInterval(heartbeat, 30000);
    // Initial check after 5 seconds
    const initial = setTimeout(heartbeat, 5000);

    return () => {
      clearInterval(interval);
      clearTimeout(initial);
    };
  }, [status]);

  // Monkey-patch window.fetch to handle offline exceptions and perform offline caching/queueing
  useEffect(() => {
    if (typeof window === "undefined") return;

    const originalFetch = window.fetch;

    window.fetch = async function (input, init) {
      // 1. Resolve request details
      const url = typeof input === "string" 
        ? input 
        : input instanceof URL 
          ? input.toString() 
          : (input as Request).url;

      const method = (init?.method || (input instanceof Request ? input.method : "GET")).toUpperCase();

      // 2. Handle Offline state
      if (!navigator.onLine) {
        // Intercept mutating requests (POST, PUT, DELETE) for syncable APIs
        if (isSyncableUrl(url, method)) {
          let body = init?.body || null;
          if (input instanceof Request && !body) {
            try {
              body = await input.clone().text();
            } catch (e) {}
          }

          const headers: Record<string, string> = {};
          if (init?.headers) {
            if (init.headers instanceof Headers) {
              init.headers.forEach((val, key) => { headers[key] = val; });
            } else if (Array.isArray(init.headers)) {
              init.headers.forEach(([key, val]) => { headers[key] = val; });
            } else {
              Object.assign(headers, init.headers);
            }
          }

          enqueueRequest(url, method, body, headers);

          // Return simulated success response
          return new Response(JSON.stringify({ success: true, offline: true, message: "Queued offline" }), {
            status: 200,
            headers: { "Content-Type": "application/json" },
          });
        }

        // Intercept GET requests and return cached version if available
        if (method === "GET") {
          const cachedData = getCachedGetResponse(url);
          if (cachedData !== null) {
            return new Response(JSON.stringify(cachedData), {
              status: 200,
              headers: { "Content-Type": "application/json" },
            });
          }
        }

        // Otherwise throw custom Offline exception
        return Promise.reject(new TypeError("Failed to fetch (offline)"));
      }

      // 3. Handle Online state (Normal Fetch with Caching)
      try {
        const response = await originalFetch(input, init);

        // Cache successful JSON GET responses
        if (response.ok && method === "GET") {
          const clone = response.clone();
          try {
            const contentType = clone.headers.get("content-type");
            if (contentType && contentType.includes("application/json")) {
              clone.json().then(data => {
                cacheGetResponse(url, data);
              }).catch(() => {});
            }
          } catch (e) {}
        }

        return response;
      } catch (error: any) {
        // Only force offline on TRUE network errors when navigator.onLine is also false
        // Don't force offline for server errors, CORS, timeouts ΓÇö those aren't "no internet"
        if (!navigator.onLine && error instanceof TypeError && (error.message.includes("Failed to fetch") || error.message.includes("NetworkError"))) {
          console.warn("[OfflineSync] Confirmed offline (navigator.onLine=false):", error.message);
          setStatus("offline");
          setIsVisible(true);
        }
        throw error;
      }
    };

    return () => {
      window.fetch = originalFetch;
    };
  }, []);

  const getUIConfig = () => {
    switch (status) {
      case "offline":
        return {
          title: "No Internet Connection",
          icon: WifiOff,
          iconColor: "text-red-500 bg-red-50 dark:bg-red-950/30",
          borderColor: "border-red-200 dark:border-red-900",
          message: "You are currently disconnected from the network node.",
          subtext: "Internet is required to function on this site. Please connect to the internet to proceed."
        };
      case "slow":
        return {
          title: "Slow Network Speed",
          icon: Activity,
          iconColor: "text-amber-500 bg-amber-50 dark:bg-amber-950/30",
          borderColor: "border-amber-200 dark:border-amber-900",
          message: "Poor network telemetry performance detected.",
          subtext: "Your performance might be impacted. A stable connection is highly recommended."
        };
      case "restored":
        return {
          title: "Connection Restored",
          icon: Wifi,
          iconColor: "text-green-500 bg-green-50 dark:bg-green-950/30",
          borderColor: "border-green-200 dark:border-green-900",
          message: "Network operational link successfully re-established.",
          subtext: "All background syncs are running. Good connectivity."
        };
      default:
        return null;
    }
  };

  const config = getUIConfig();

  if (!isVisible || !config) return null;

  const Icon = config.icon;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-slate-900/60 backdrop-blur-md px-4 pointer-events-auto select-none">
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          exit={{ opacity: 0, scale: 0.95 }}
          className={`bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] max-w-2xl w-full shadow-2xl border ${config.borderColor} relative flex flex-col items-center text-center backdrop-blur-xl`}
        >
          <div className={`w-16 h-16 rounded-full flex items-center justify-center mb-6 ${config.iconColor}`}>
            <Icon size={32} />
          </div>

          <h3 className="font-display text-2xl font-bold text-slate-900 dark:text-white mb-4">{config.title}</h3>

          <div className="w-full px-2 flex flex-col gap-3 items-center justify-center">
            <p className="text-sm text-slate-600 dark:text-slate-300 leading-relaxed text-justify">
              {config.message}
            </p>
            <p className="text-sm font-bold text-slate-700 dark:text-slate-200 leading-relaxed text-justify border-t border-slate-100 dark:border-slate-800 pt-3 w-full">
              {config.subtext}
            </p>
          </div>

          {/* Acknowledge button is only available for slow connections, NOT when fully offline */}
          {status === "slow" && (
            <button 
              onClick={() => setIsVisible(false)}
              className="mt-6 px-6 py-2 rounded-xl bg-slate-100 hover:bg-slate-200 dark:bg-slate-800 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-300 font-semibold text-xs transition-all cursor-pointer"
            >
              Acknowledge
            </button>
          )}
        </motion.div>
      </div>
    </AnimatePresence>
  );
}

import React from 'react';

interface LatexifyLogoProps {
  size?: number;
  className?: string;
  style?: React.CSSProperties;
  color?: string; // Kept for interface compatibility but ignored by raster image
  forceTheme?: 'light' | 'dark'; // Force a specific theme representation
}

export default function LatexifyLogo({ size = 32, className = '', style = {}, forceTheme }: LatexifyLogoProps) {
  // Determine if it should be inverted (white text logo)
  const isInverted = className.includes('text-white') || className.includes('invert') || className.includes('text-light');

  let filterStyle = style.filter || undefined;
  if (isInverted || forceTheme === 'dark') {
    filterStyle = 'brightness(0) invert(1)';
  } else if (forceTheme === 'light') {
    filterStyle = 'none';
  }

  const imgClass = forceTheme === 'light'
    ? 'transition-all duration-300'
    : 'dark:brightness-0 dark:invert transition-all duration-300';

  return (
    <div className={className} style={{ ...style, display: 'flex', alignItems: 'center', height: size }}>
      <img
        src="/logo.png"
        alt="Latexify Logo"
        className={imgClass}
        style={{ 
          height: '100%', 
          width: 'auto', 
          objectFit: 'contain', 
          maxWidth: '240px',
          filter: filterStyle
        }}
      />
    </div>
  );
}

