                      {i < metadataOrgs.length - 1 ? ' ΓÇó' : ''}
                    </span>
                  ))
                ) : (
                  <span className="text-sm opacity-50">Not available</span>
                )}
      </div>

      {/* Health Score Warning Popup */}
      <AnimatePresence>
        {showHealthWarning && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
