  data: PbServerSession | null;
  status: SessionStatus;
  update: (data?: any) => Promise<void>;
}

const SessionContext = createContext<SessionContextValue | null>(null);

interface SessionProviderProps {
  children: ReactNode;
  refetchInterval?: number;
  refetchOnWindowFocus?: boolean;
}

export function SessionProvider({ children, refetchInterval, refetchOnWindowFocus = false }: SessionProviderProps) {
  const [data, setData] = useState<PbServerSession | null>(null);
  const [status, setStatus] = useState<SessionStatus>("loading");

  const isFetching = useRef(false);

  const update = useCallback(async (data?: any) => {
    if (isFetching.current) return;
    isFetching.current = true;
    try {
      const res = await fetch("/api/auth/pb-session");
      if (res.ok) {
        const json = await res.json();
        if (json.user) {
          setData(json);
          setStatus("authenticated");
        } else {
          setData(null);
          setStatus("unauthenticated");
        }
      } else {
        setData(null);
        setStatus("unauthenticated");
      }
    } catch (err) {
      setData(null);
      setStatus("unauthenticated");
    } finally {
      isFetching.current = false;
    }
  }, []);

  useEffect(() => {
    update();
  }, [update]);

  useEffect(() => {
    if (!refetchInterval) return;
    const interval = setInterval(update, refetchInterval * 1000);
    return () => clearInterval(interval);
  }, [refetchInterval, update]);

  useEffect(() => {
    if (!refetchOnWindowFocus) return;
    const onFocus = () => update();
    window.addEventListener("focus", onFocus);
    return () => window.removeEventListener("focus", onFocus);
  }, [refetchOnWindowFocus, update]);

  return (
    <SessionContext.Provider value={{ data, status, update }}>
      {children}
    </SessionContext.Provider>
  );
}

export function useSession(options?: { required?: boolean; onUnauthenticated?: () => void }) {
  const context = useContext(SessionContext);
  const router = useRouter();

  if (!context) {
    throw new Error("useSession must be used within a SessionProvider");
  }

  useEffect(() => {
    if (options?.required && context.status === "unauthenticated") {
      if (options.onUnauthenticated) {
        options.onUnauthenticated();
      } else {
        router.push("/login");
      }
    }
  }, [context.status, options, router]);

  return context;
}

export async function signOut(options?: { callbackUrl?: string }) {
  try {
    await fetch("/api/auth/pb-logout", { method: "POST" });
  } catch { }
  if (typeof window !== "undefined") {
    window.location.href = options?.callbackUrl || "/login";
  }
}

export function signIn() {
  if (typeof window !== "undefined") {
    window.location.href = "/login";
  }
}

/**
 * PocketBase server-client singleton & helpers.
 *
 * Usage (server-side / API routes):
 *   import { pb } from '@/lib/pb';
 *   const records = await pb.collection('projects').getFullList();
 *
 * Auth flows:
 *   - User auth: pb.collection('users').authWithPassword(email, password)
 *   - Admin auth: await pbAdmin()
 *
 * After login, store pb.authStore.token / pb.authStore.record in a cookie
 * and rehydrate on each request via setToken().
 */

import PocketBase from 'pocketbase';

const PB_URL = process.env.POCKETBASE_URL || 'http://127.0.0.1:8090';

/** Fresh unauthenticated client (use for public reads). */
export function createPb() {
  return new PocketBase(PB_URL);
}

/**
 * Server-side PocketBase client rehydrated from an auth token cookie.
 * Automatically loads the user record so authStore.record is available.
 */
export async function authFromToken(token: string) {
  const pb = new PocketBase(PB_URL);
  pb.authStore.save(token, null);
  if (pb.authStore.isValid) {
    try {
      await pb.collection('users').authRefresh({ requestKey: 'auth_refresh' });
    } catch {
      pb.authStore.clear();
    }
  }
  return pb;
}

/**
 * Admin-authenticated PocketBase client.
 * Cached in-memory so we don't re-auth on every request.
 */
let _adminPb: PocketBase | null = null;

export async function pbAdmin(): Promise<PocketBase> {
  if (_adminPb) {
    try {
      await _adminPb.collection('_superusers').getList(1, 1, { requestKey: 'ping' });
      return _adminPb;
    } catch {
      _adminPb = null;
    }
  }

  const pb = new PocketBase(PB_URL);
  let email = process.env.POCKETBASE_ADMIN_EMAIL || 'admin@latexify.io';
  let password = process.env.POCKETBASE_ADMIN_PASSWORD || 'admin123456';

  try {
    const fs = require('fs');
    const path = require('path');
    const credsPath = path.join(process.cwd(), 'pb_data', 'admin_creds.json');
    if (fs.existsSync(credsPath)) {
      const data = JSON.parse(fs.readFileSync(credsPath, 'utf8'));
      if (data.email) email = data.email;
      if (data.password) password = data.password;
    }
  } catch (err) {
    // Non-fatal
  }

  // PocketBase v0.23+: admins are now _superusers collection
  await pb.collection('_superusers').authWithPassword(email, password);
  _adminPb = pb;
  return pb;
}

/**
 * Convert PocketBase record list to plain objects with
 * id / created / updated mapped to the Prisma convention.
 */
export function mapRecord<T = any>(r: any): T {
  if (!r) return null as any;
  const o: Record<string, any> = { id: r.id };
  if (r.created) o.createdAt = r.created;
  if (r.updated) o.updatedAt = r.updated;
  for (const k of Object.keys(r)) {
    if (!['id', 'collectionId', 'collectionName', 'created', 'updated'].includes(k)) {
      o[k] = r[k];
    }
  }
  return o as T;
}

export function mapList<T = any>(list: any[]): T[] {
  return list.map((r) => mapRecord<T>(r));
}

/**
 * Prisma-compatible PocketBase adapter.
 *
 * Drop-in replacement ΓÇö import { prisma } from "@/lib/prisma" still works,
 * but all queries are forwarded to PocketBase collections.
 *
 * Supported operations:
 *   prisma.model.findUnique({ where: { id } })
 *   prisma.model.findFirst({ where })
 *   prisma.model.findMany({ where, orderBy, skip, take })
 *   prisma.model.create({ data })
 *   prisma.model.update({ where: { id }, data })
 *   prisma.model.upsert({ where: { id }, create, update })
 *   prisma.model.delete({ where: { id } })
 *   prisma.model.count({ where })
 *   prisma.model.findMany({ where: { id: { in: [...] } } })
 *   prisma.model.createMany({ data })
 *   prisma.model.updateMany({ where, data })
 *   prisma.model.deleteMany({ where })
 */

import PocketBase from 'pocketbase';
import { createPb, pbAdmin, mapRecord, mapList } from './pb';

type WhereClause = Record<string, any>;

/** Format a value for PocketBase filter ΓÇö dates use PocketBase 0.27 format (space, not T). */
function pbDateStr(d: Date): string {
  return d.toISOString().replace('T', ' ');
}

function fmtFilterVal(v: any): string {
  if (v instanceof Date) return `"${pbDateStr(v)}"`;
  if (typeof v === 'string') return `"${v}"`;
  if (typeof v === 'number' || typeof v === 'boolean') return String(v);
  if (v === null) return 'null';
  return `"${String(v)}"`;
}

/** Convert a Prisma-style where clause to PocketBase filter string. */
function toFilter(where?: WhereClause): string | undefined {
  if (!where) return undefined;
  const parts: string[] = [];
  for (const [key, val] of Object.entries(where)) {
    if (val === null || val === undefined) continue;
    if (key === 'id') {
      parts.push(`id = "${val}"`);
    } else if (key === 'NOT') {
      // skip NOT for now
    } else if (key === 'AND') {
      // skip AND for now
    } else if (key === 'OR') {
      // skip OR for now
    } else if (typeof val === 'object' && val !== null && 'in' in val && Array.isArray(val.in)) {
      const items = val.in.map((v: any) => `"${v}"`).join(',');
      parts.push(`${key} ${val.in.length ? 'IN (' + items + ')' : 'id != id'}`);
    } else if (typeof val === 'object' && val !== null && 'not' in val) {
      parts.push(`${key} != ${fmtFilterVal(val.not)}`);
    } else if (typeof val === 'object' && val !== null && 'contains' in val) {
      parts.push(`${key} ~ "${val.contains}"`);
    } else if (typeof val === 'object' && val !== null && 'startsWith' in val) {
      parts.push(`${key} ~ "${val.startsWith}"`);
    } else if (typeof val === 'object' && val !== null && 'gt' in val) {
      parts.push(`${key} > ${fmtFilterVal(val.gt)}`);
    } else if (typeof val === 'object' && val !== null && 'gte' in val) {
      parts.push(`${key} >= ${fmtFilterVal(val.gte)}`);
    } else if (typeof val === 'object' && val !== null && 'lt' in val) {
      parts.push(`${key} < ${fmtFilterVal(val.lt)}`);
    } else if (typeof val === 'object' && val !== null && 'lte' in val) {
      parts.push(`${key} <= ${fmtFilterVal(val.lte)}`);
    } else if (typeof val === 'string') {
      parts.push(`${key} = "${val}"`);
    } else if (typeof val === 'number' || typeof val === 'boolean') {
      parts.push(`${key} = ${val}`);
    } else if (val instanceof Date) {
      parts.push(`${key} = "${pbDateStr(val)}"`);
    } else if (typeof val === 'object' && val !== null && !Array.isArray(val)) {
      const isOperator = Object.keys(val).some(k => ['in','not','contains','startsWith','gt','gte','lt','lte','notIn'].includes(k));
      if (isOperator) {
        parts.push(`${key} = "${String(val)}"`);
      } else {
        for (const [subKey, subVal] of Object.entries(val)) {
          if (subVal === null || subVal === undefined) continue;
          parts.push(`${subKey} = ${fmtFilterVal(subVal)}`);
        }
      }
    } else {
      parts.push(`${key} = "${String(val)}"`);
    }
  }
  return parts.length ? parts.join(' && ') : undefined;
}

/** Convert Prisma orderBy to PocketBase sort string. */
function toSort(orderBy?: Record<string, 'asc' | 'desc'> | Record<string, 'asc' | 'desc'>[]): string | undefined {
  if (!orderBy) return undefined;
  const items = Array.isArray(orderBy) ? orderBy : [orderBy];
  const s = items.map((o) => {
    const [key, dir] = Object.entries(o)[0];
    return dir === 'desc' ? `-${key}` : key;
  }).join(',');
  return s || undefined;
}

/** Expand relation fields (Prisma include ΓåÆ PocketBase expand). Strips invalid values like _count. */
function toExpand(include?: Record<string, any>): string | undefined {
  if (!include) return undefined;
  const s = Object.keys(include).filter((k) => !k.startsWith('_')).join(',');
  return s || undefined;
}

function deepRenameKeys(obj: any, map: Record<string, string>): any {
  if (Array.isArray(obj)) return obj.map((v) => deepRenameKeys(v, map));
  if (obj && typeof obj === 'object') {
    const result: Record<string, any> = {};
    for (const [k, v] of Object.entries(obj)) {
      const newKey = map[k] || k;
      result[newKey] = v && typeof v === 'object' ? deepRenameKeys(v, map) : v;
    }
    return result;
  }
  return obj;
}

/**
 * Build a per-collection proxy that translates Prisma method calls
 * into PocketBase SDK calls.
 */
function collectionProxy(collectionName: string) {
  return new Proxy(
    {},
    {
      get(_, method: string) {
        return async (args: any = {}) => {
          const pb = args._pb || (await getClient());
          const col = pb.collection(collectionName);

          if (method === 'aggregate') {
            try {
              const filter = toFilter(args?.where);
              const opts: Record<string, any> = { requestKey: `${collectionName}_aggregate` };
              if (filter) opts.filter = filter;
              const all = await col.getFullList(opts);
              const result: any = { _count: {}, _sum: {}, _avg: {}, _min: {}, _max: {} };
              if (args._count) {
                result._count = Object.fromEntries(Object.keys(args._count).map(k => [k, all.length]));
              }
              if (args._sum) {
                for (const field of Object.keys(args._sum)) {
                  result._sum[field] = all.reduce((s: number, r: any) => s + (Number(r[field]) || 0), 0);
                }
              }
              if (args._avg) {
                for (const field of Object.keys(args._avg)) {
                  const sum = all.reduce((s: number, r: any) => s + (Number(r[field]) || 0), 0);
                  result._avg[field] = all.length ? sum / all.length : 0;
                }
              }
              if (args._min) {
                for (const field of Object.keys(args._min)) {
                  result._min[field] = all.length ? Math.min(...all.map((r: any) => Number(r[field]) || 0)) : 0;
                }
              }
              if (args._max) {
                for (const field of Object.keys(args._max)) {
                  result._max[field] = all.length ? Math.max(...all.map((r: any) => Number(r[field]) || 0)) : 0;
                }
              }
              return result;
            } catch {
              return { _count: {}, _sum: {}, _avg: {}, _min: {}, _max: {} };
            }
          }

          if (method === 'groupBy') {
            try {
              const filter = toFilter(args?.where);
              const opts: Record<string, any> = { requestKey: `${collectionName}_groupBy` };
              if (filter) opts.filter = filter;
              const all = await col.getFullList(opts);
              const byFields = args.by || [];
              const groups: Record<string, any[]> = {};
              for (const rec of all) {
                const key = byFields.map((f: string) => String(rec[f] ?? '')).join('||');
                if (!groups[key]) groups[key] = [];
                groups[key].push(rec);
              }
              return Object.entries(groups).map(([_, group]) => {
                const entry: any = {};
                // Include the 'by' fields from the first record in the group
                for (const field of byFields) {
                  entry[field] = group[0]?.[field] ?? null;
                }
                if (args._count) {
                  entry._count = Object.fromEntries(Object.keys(args._count).map(k => [k, group.length]));
                }
                if (args._sum) {
                  entry._sum = Object.fromEntries(
                    Object.keys(args._sum).map(k => [k, group.reduce((s: number, r: any) => s + (Number(r[k]) || 0), 0)])
                  );
                }
                // Include other aggregate keys as needed
                return entry;
              });
            } catch {
              return [];
            }
          }

          switch (method) {
            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'findUnique': {
              const id = args?.where?.id;
              if (id) {
                const expand = toExpand(args?.include);
                const opts: Record<string, any> = { requestKey: `${collectionName}_findUnique_${id}` };
                if (expand) opts.expand = expand;
                try {
                  const r = await col.getOne(id, opts);
                  return mapRecord(r as any);
                } catch {
                  return null;
                }
              }
                // fallback to findFirst
              const filter = toFilter(args?.where);
              const opts2: Record<string, any> = { requestKey: `${collectionName}_findUnique_filter` };
              if (filter) opts2.filter = filter;
              const expand2 = toExpand(args?.include);
              if (expand2) opts2.expand = expand2;
              try {
                const list2 = await col.getList(1, 1, opts2);
                return list2.items.length ? mapRecord(list2.items[0] as any) : null;
              } catch {
                return null;
              }
            }

            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'findFirst': {
              const filter = toFilter(args?.where);
              const sort = toSort(args?.orderBy);
              const opts: Record<string, any> = { requestKey: `${collectionName}_findFirst` };
              if (filter) opts.filter = filter;
              if (sort) opts.sort = sort;
              const expand = toExpand(args?.include);
              if (expand) opts.expand = expand;
              try {
                const list = await col.getList(1, 1, opts);
                return list.items.length ? mapRecord(list.items[0] as any) : null;
              } catch {
                return null;
              }
            }

            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'findMany': {
              const { skip = 0, take = 30 } = args || {};
              const page = Math.floor(skip / take) + 1;
              const filter = toFilter(args?.where);
              const sort = toSort(args?.orderBy);
              const opts: Record<string, any> = { requestKey: `${collectionName}_findMany` };
              if (filter) opts.filter = filter;
              if (sort) opts.sort = sort;
              const expand = toExpand(args?.include);
              if (expand) opts.expand = expand;
              try {
                const list = await col.getList(page, take, opts);
                return mapList(list.items as any[]);
              } catch {
                return [];
              }
            }

            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'create': {
              const r = await col.create(args?.data, {
                requestKey: `${collectionName}_create`,
              });
              return mapRecord(r as any);
            }

            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'createMany': {
              const dataArr = args?.data || [];
              const results = [];
              for (const item of dataArr) {
                const r = await col.create(item, {
                  requestKey: `${collectionName}_createMany_${item.id}`,
                });
                results.push(mapRecord(r as any));
              }
              return results;
            }

            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'update': {
              const id = args?.where?.id;
              if (!id) throw new Error(`update requires where.id for collection ${collectionName}`);
              try {
                const r = await col.update(id, args?.data, {
                  requestKey: `${collectionName}_update_${id}`,
                });
                return mapRecord(r as any);
              } catch (e: any) {
                if (e?.status === 404) return null;
                throw e;
              }
            }

            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'upsert': {
              try {
                const uFilter = toFilter(args?.where);
                const uOpts: Record<string, any> = { requestKey: `${collectionName}_upsert_check` };
                if (uFilter) uOpts.filter = uFilter;
                const existing = await col.getList(1, 1, uOpts);
                if (existing.items.length) {
                  const r = await col.update(existing.items[0].id, args?.update, {
                    requestKey: `${collectionName}_upsert_update`,
                  });
                  return mapRecord(r as any);
                }
                const r = await col.create(args?.create, {
                  requestKey: `${collectionName}_upsert_create`,
                });
                return mapRecord(r as any);
              } catch (e: any) {
                if (e?.status === 404) return null;
                throw e;
              }
            }

            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'delete': {
              const id = args?.where?.id;
              if (!id) throw new Error(`delete requires where.id for collection ${collectionName}`);
              await col.delete(id, {
                requestKey: `${collectionName}_delete_${id}`,
              });
              return { id };
            }

            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'deleteMany': {
              const dmFilter = toFilter(args?.where);
              const dmOpts: Record<string, any> = { requestKey: `${collectionName}_deleteMany_list` };
              if (dmFilter) dmOpts.filter = dmFilter;
              // PB has no bulk delete ΓÇö fetch matching IDs then delete one by one
              const list = await col.getFullList(dmOpts);
              for (const item of list) {
                await col.delete(item.id, {
                  requestKey: `${collectionName}_deleteMany_${item.id}`,
                });
              }
              return { count: list.length };
            }

            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'updateMany': {
              const umFilter = toFilter(args?.where);
              const umOpts: Record<string, any> = { requestKey: `${collectionName}_updateMany_list` };
              if (umFilter) umOpts.filter = umFilter;
              const list = await col.getFullList(umOpts);
              for (const item of list) {
                await col.update(item.id, args?.data, {
                  requestKey: `${collectionName}_updateMany_${item.id}`,
                });
              }
              return { count: list.length };
            }

            // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
            case 'count': {
              const filter = toFilter(args?.where);
              const opts: Record<string, any> = { requestKey: `${collectionName}_count` };
              if (filter) opts.filter = filter;
              try {
                const result = await col.getList(1, 1, opts);
                return result.totalItems;
              } catch {
                return 0;
              }
            }

            default:
              throw new Error(`Prisma method '${method}' not implemented in PocketBase adapter`);
          }
        };
      },
    }
  );
}

/** Get a PocketBase admin client with caching and fallback. */
let _cachedClient: PocketBase | null = null;
async function getClient(): Promise<PocketBase> {
  if (_cachedClient) return _cachedClient;
  try {
    const client = await pbAdmin();
    _cachedClient = client;
    return client;
  } catch (err) {
    console.error('[pb-adapter] Failed to get admin client, using unauthenticated client:', err);
    const client = createPb();
    _cachedClient = client;
    return client;
  }
}

